import{_ as a,o as i,c as o,a2 as t}from"./chunks/framework.CE5oItKu.js";const m=JSON.parse('{"title":"RBAC Views","description":"","frontmatter":{},"headers":[],"relativePath":"mango-ui/packages/rbac/src/views/README.md","filePath":"mango-ui/packages/rbac/src/views/README.md"}'),d={name:"mango-ui/packages/rbac/src/views/README.md"};function l(c,e,s,n,r,p){return i(),o("div",null,[...e[0]||(e[0]=[t(`<h1 id="rbac-views" tabindex="-1">RBAC Views <a class="header-anchor" href="#rbac-views" aria-label="Permalink to &quot;RBAC Views&quot;">​</a></h1><h2 id="_1-概览" tabindex="-1">1. 概览 <a class="header-anchor" href="#_1-概览" aria-label="Permalink to &quot;1. 概览&quot;">​</a></h2><p>本入口说明 <code>@mango/rbac</code> 的权限、菜单、角色、用户、组织、岗位、应用和菜单包页面。它们是 RBAC 管理页面入口，不是独立复用组件库。</p><h2 id="_2-功能清单" tabindex="-1">2. 功能清单 <a class="header-anchor" href="#_2-功能清单" aria-label="Permalink to &quot;2. 功能清单&quot;">​</a></h2><p>来自 <code>@mango/rbac</code>：</p><ul><li><code>MenuView</code></li><li><code>MenuPackageView</code></li><li><code>RoleView</code></li><li><code>UserView</code></li><li><code>OrgView</code></li><li><code>PermissionView</code></li><li><code>AppView</code></li><li><code>PostView</code></li><li><code>appApi</code>、<code>menuApi</code>、<code>menuPackageApi</code>、<code>orgApi</code>、<code>postApi</code>、<code>roleApi</code>、<code>userApi</code> 相关导出。</li></ul><p><code>@mango/rbac</code> 当前没有独立 <code>admin-pages</code> 注册入口；页面通常由 admin-shell 或业务应用按菜单 component 映射引用。</p><ul><li>维护应用、菜单、页面 component key 和权限资源。</li><li>维护角色授权、用户、组织和岗位。</li><li>排查登录后菜单、按钮权限和组织数据。</li><li>业务项目接入 Mango 后配置后台 RBAC 基础数据。</li></ul><h2 id="_3-页面入口" tabindex="-1">3. 页面入口 <a class="header-anchor" href="#_3-页面入口" aria-label="Permalink to &quot;3. 页面入口&quot;">​</a></h2><p>常用页面 key 映射：</p><table tabindex="0"><thead><tr><th>页面 key</th><th>组件</th></tr></thead><tbody><tr><td><code>system/menu/index</code></td><td><code>MenuView</code></td></tr><tr><td><code>system/menu-package/index</code></td><td><code>MenuPackageView</code></td></tr><tr><td><code>system/role/index</code></td><td><code>RoleView</code></td></tr><tr><td><code>system/user/index</code></td><td><code>UserView</code></td></tr><tr><td><code>system/org/index</code></td><td><code>OrgView</code></td></tr><tr><td><code>system/permission/index</code></td><td><code>PermissionView</code></td></tr><tr><td><code>system/app/index</code></td><td><code>AppView</code></td></tr><tr><td><code>system/post/index</code></td><td><code>PostView</code></td></tr></tbody></table><p>接入示例：</p><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { MenuView, RoleView, UserView } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@mango/rbac&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@mango/rbac/style.css&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span></code></pre></div><p>业务应用按路由或菜单 component 映射页面组件。页面 key 需要和后端 authorization 菜单资源保持一致。</p><p>页面组件不对外定义 props 或事件；数据来源是各 <code>src/api/*.ts</code> API 封装。</p><p>页面之间通过后端资源关系协作：</p><ul><li>应用和菜单包影响菜单归属。</li><li>菜单和权限影响按钮显示和访问控制。</li><li>用户、组织、岗位和角色影响授权结果。</li></ul><h2 id="_4-后端依赖" tabindex="-1">4. 后端依赖 <a class="header-anchor" href="#_4-后端依赖" aria-label="Permalink to &quot;4. 后端依赖&quot;">​</a></h2><ul><li>后端模块：<code>mango-platform/mango-authorization</code>、<code>mango-platform/mango-identity</code>、<code>mango-platform/mango-org</code>、<code>mango-platform/mango-access</code>。</li><li>API 前缀覆盖 app、menu、menu-package、org、post、role、user 相关接口，具体路径以 <code>src/api/*.ts</code> 为准。</li><li>登录菜单闭环还依赖 <code>@mango/auth</code> 和 admin-shell。</li></ul><h2 id="_5-管理入口" tabindex="-1">5. 管理入口 <a class="header-anchor" href="#_5-管理入口" aria-label="Permalink to &quot;5. 管理入口&quot;">​</a></h2><ul><li>页面中的菜单、角色、用户、组织和岗位数据由后端按租户、数据权限和接口权限校验。</li><li>前端按钮权限来自菜单资源和用户权限集合。</li><li>菜单 component key 需要能映射到真实页面组件，否则登录后会出现空页面或找不到组件。</li></ul><h2 id="_6-问题排查" tabindex="-1">6. 问题排查 <a class="header-anchor" href="#_6-问题排查" aria-label="Permalink to &quot;6. 问题排查&quot;">​</a></h2><ul><li>菜单能看到但页面打不开时，检查 component key 与前端注册映射。</li><li>按钮不显示时，检查后端资源同步、角色授权和用户权限集合。</li><li>用户或组织为空时，检查 identity/org 后端数据和租户上下文。</li></ul><p>菜单打不开排障顺序：</p><ol><li><code>/authorization/menus/user?fmt=tree&amp;appCode=internal-admin</code> 返回目标菜单。</li><li>菜单的 <code>component</code> 字段命中上方页面 key 映射。</li><li>当前用户角色已绑定菜单和权限资源。</li><li>当前租户已绑定目标应用。</li><li>前端已引入 <code>@mango/rbac/style.css</code>，并在路由或页面注册表中绑定对应组件。</li><li>浏览器 console 和 network 没有未解释的模块加载、接口 401/403/404 错误。</li></ol><h2 id="_7-相关文档" tabindex="-1">7. 相关文档 <a class="header-anchor" href="#_7-相关文档" aria-label="Permalink to &quot;7. 相关文档&quot;">​</a></h2><ul><li><a href="./../../README">@mango/rbac README</a></li><li><a href="./../../../../../mango/mango-platform/mango-authorization/README">Authorization 后端 README</a></li><li><a href="./../../../../../mango/mango-platform/mango-identity/README">Identity 后端 README</a></li><li><a href="./../../../../../mango/mango-platform/mango-access/README">Access 后端 README</a></li><li><a href="./../../../../../mango-docs/capabilities/README">能力地图</a></li><li><a href="./../../../../../mango-pmo/rules/08-capability-docs">能力说明维护规范</a></li></ul>`,27)])])}const u=a(d,[["render",l]]);export{m as __pageData,u as default};
